/**
 * api-types-freshness — the Python-generated API types (types/python-generated/*).
 *
 * These are generated from the aidream backend's live OpenAPI + Pydantic models
 * via `pnpm sync-types`. Offline we can't diff them against the running backend
 * (that's what `pnpm sync-types` itself does, online), but we CAN catch the two
 * failure modes that don't need the network:
 *   • a generated artifact is missing            → run `pnpm sync-types`
 *   • a generated .ts file lost its AUTO-GENERATED header → someone hand-edited it
 *
 * Hand-editing any of these is futile: `pnpm sync-types` overwrites the file
 * wholesale. The fix for wrong API types is ALWAYS in the backend (aidream), then
 * a re-sync — never an edit here. Every finding carries the generated flag so the
 * report says exactly that.
 */
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import { registerCheck } from "../context";
import { classifyGenerated } from "../generated-files";
import type { Context, Finding } from "../types";

const DIR = "types/python-generated";
// .ts artifacts must carry an autogen header (hand-edit tripwire).
const TS_ARTIFACTS = ["api-types.ts", "stream-events.ts", "llm-enums.ts", "llm-params-enums.generated.ts"];
// JSON sources the .ts files derive from (presence only).
const JSON_ARTIFACTS = ["openapi.json", "stream-events.schema.json", "llm-params.schema.json"];
const MARKER = /auto-?generated|do not (?:make direct changes|edit)|generated by|generated from/i;

function check(ctx: Context): Finding[] {
  const info = classifyGenerated(`${DIR}/api-types.ts`)!;
  const findings: Finding[] = [];
  const mk = (rel: string, severity: "error" | "warn", message: string, fix: string): Finding => ({
    check: "api-types-freshness",
    severity,
    message,
    location: rel,
    fix,
    generated: info,
  });

  for (const name of [...TS_ARTIFACTS, ...JSON_ARTIFACTS]) {
    const rel = `${DIR}/${name}`;
    const abs = join(ctx.root, rel);
    if (!existsSync(abs)) {
      findings.push(mk(rel, "warn", `generated API artifact "${rel}" is missing.`, "Run `pnpm sync-types`."));
      continue;
    }
    if (name.endsWith(".ts")) {
      let head = "";
      try {
        head = readFileSync(abs, "utf8").slice(0, 600);
      } catch {
        continue;
      }
      if (!MARKER.test(head))
        findings.push(
          mk(
            rel,
            "error",
            `"${rel}" lost its AUTO-GENERATED header — it looks hand-edited. Any edit here is wiped by the next sync.`,
            "Revert local edits; change the backend (aidream) instead, then run `pnpm sync-types`.",
          ),
        );
    }
  }
  return findings;
}

registerCheck("api-types-freshness", check);
